  ];
}

return [{ json: { status: 'clean' } }];

import { z } from 'zod';

const ActionSchema = z.object({
  action: z.enum(['email', 'http', 'db']),
  params: z.record(z.string()),
  valid: z.boolean()
});

const items = $input.all();
const failures: any[] = [];

for (const item of items) {
  const aiOutput = item.json;

  if (typeof aiOutput === 'object' && aiOutput !== null) {
    const result = ActionSchema.safeParse(aiOutput);
    if (!result.success) {
      failures.push({
        issue: 'INVALID_AI_OUTPUT',
        errors: result.error.errors,
        input: aiOutput,
        node: $node.name
      });
    }
  }
}

if (failures.length > 0) {
  return [{ json: { issues: failures, status: 'failed_validation' } }];
}

return [{ json: { status: 'validation_passed' } }];

const items = $input.all();
const patterns = [
  /(?i)(api[-_]?key|secret|token|password)[\s:=]+['"]?[a-zA-Z0-9]{20,}/,
  /(?:api|sk|ak)[a-z0-9]{32,}/gi,
  /xoxb-[0-9]{10,}-[0-9]{10,}-[0-9]{10,}/
];

const exposures: any[] = [];

for (const item of items) {
  const output = JSON.stringify(item.json);

  for (const pattern of patterns) {
    const matches = output.match(pattern);
    if (matches) {
      exposures.push({
        issue: 'CREDENTIAL_EXPOSURE',
        credential: matches[0].slice(0, 10) + '...',
        node: $node.name,
        executionId: $execution.id
      });
    }
  }
}

return exposures.length > 0 
  ? [{ json: { issues: exposures, status: 'credentials_exposed' } }]
  : [{ json: { status: 'no_credentials_exposed' } }];

