const items = $input.all();
const safeOutputs: any[] = [];

const fallback = { action: 'none', params: {}, valid: false };

for (const item of items) {
  try {
    const aiOutput = item.json;

    // Expected structure for action nodes
    const parsed = {
      action: aiOutput?.action || 'none',
      params: aiOutput?.params || {},
      valid: true
    };

    safeOutputs.push({ json: parsed });
  } catch (error) {
    safeOutputs.push({ json: fallback });
  }
}

return safeOutputs;

const items = $input.all();
const now = new Date();
const TWENTY_FOUR_HOURS = 24 * 60 * 60 * 1000;

const freshContext: any[] = [];

for (const item of items) {
  const memoryItems = item.json;

  if (Array.isArray(memoryItems)) {
    const filtered = memoryItems.filter((msg: any) => {
      const msgTime = new Date(msg.timestamp || msg.createdAt);
      return (now.getTime() - msgTime.getTime()) < TWENTY_FOUR_HOURS;
    });

    freshContext.push({ json: filtered });
  } else {
    freshContext.push(item);
  }
}

return freshContext.length > 0 ? freshContext : [{ json: [] }];

