import { Vex } from '@vex_dev/sdk';

// Initialize Vex in n8n workflow
const vex = new Vex({
  projectId: 'your-n8n-project',
  webhookToken: $env.VEX_WEBHOOK_TOKEN,
  framework: 'n8n-ai-agent'
});

// Add after every AI Agent node
export async function testAgentOutput(items: any[]) {
  const results = [];

  for (const item of items) {
    // Test for all 4 failure modes
    const tests = await Promise.all([
      vex.test.recursiveLoop($execution.id, $workflow.id),
      vex.test.schemaValidation(item.json, 'ai-agent-output'),
      vex.test.credentialExposure(item.json),
      vex.test.contextFreshness(item.json)
    ]);

    const hasFailures = tests.some(t => !t.pass);

    results.push({
      json: {
        ...item.json,
        vex: {
          passed: !hasFailures,
          issues: tests.filter(t => !t.pass),
          fixed: hasFailures ? await vex.autoFix(item.json) : null
        }
      }
    });
  }

  // Block execution on failures
  if (results.some(r => !r.json.vex.passed)) {
    throw new Error('Vex detected AI Agent failures');
  }

  return results;
}
